import java.io.FileWriter;
import java.io.IOException;
import java.util.List;

public void writeToCsvFile(List<double[][]> featuresList, List<Integer> labelsList, String filepath) throws IOException {
    try (FileWriter writer = new FileWriter(filepath)) {
        for (int i = 0; i < featuresList.size(); i++) {
            double[][] feature = featuresList.get(i);
            int label = labelsList.get(i);

            for (double[] row : feature) {
                for (double value : row) {
                    writer.append(Double.toString(value)).append(",");
                }
            }

            writer.append(Integer.toString(label)).append("\n");
        }
    }
}
```
