在 Java 端你可以使用以下方法调用这个 Python 脚本:

```java
import java.io.IOException;
import java.io.OutputStream;

public void generateNumpyFile(double[][] data, String pythonScriptPath) throws IOException {
    ProcessBuilder pb = new ProcessBuilder("python", pythonScriptPath);
    Process p = pb.start();

    try (OutputStream os = p.getOutputStream()) {
        for (double[] row : data) {
            for (double value : row) {
                os.write(doubleToBytes(value));
            }
        }
    }

    // 获取脚本的输出结果，确保完成
    try {
        p.waitFor();
    } catch (InterruptedException e) {
        Thread.currentThread().interrupt(); // 保持中断状态
        throw new IOException("Interrupted while waiting for the Python process", e);
    }
}

private byte[] doubleToBytes(double value) {
    long bits = Double.doubleToRawLongBits(value);
    byte[] bytes = new byte[8];
    for (int i = 7; i >= 0; i--) {
        bytes[i] = (byte) (bits & 0xff);
        bits >>= 8;
    }
    return bytes;
}
```

